(function(w){"use strict";const ID="temperature";function toC(v,u){return u==="c"?v:u==="f"?(v-32)*5/9:v-273.15}function fromC(v,u){return u==="c"?v:u==="f"?v*9/5+32:v+273.15}function compute(x){const v=Number(x.value);if(!Number.isFinite(v)||!["c","f","k"].includes(x.from)||!["c","f","k"].includes(x.to))return{error:"값과 단위를 올바르게 선택해 주세요."};const c=toC(v,x.from);if(c<-273.15-1e-9)return{error:"절대영도보다 낮은 온도는 변환할 수 없습니다."};return{value:fromC(c,x.to)}}function render(root,api){const opts=`<option value="c">섭씨 °C</option><option value="f">화씨 °F</option><option value="k">켈빈 K</option>`;root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>변환할 온도</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>기준 단위</label><select class="hm-calc-select">${opts}</select></div><div class="hm-calc-field"><label>변환 단위</label><select class="hm-calc-select">${opts}</select></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">변환하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),sels=root.querySelectorAll("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");sels[1].value="f";go.addEventListener("click",()=>{const r=compute({value:api.parseNumber(input.value),from:sels[0].value,to:sels[1].value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const unit=sels[1].value==="c"?"°C":sels[1].value==="f"?"°F":"K";api.setResult(res,api.resultCard("변환 결과",`${api.formatNumber(r.value,6)} ${unit}`));});}w.HM_CALC.register(ID,{compute,render});})(window);
